import { useState, useRef, useEffect, useMemo } from 'react';

/* ───── Design tokens (matching Aura dark theme) ───── */
const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  surface2: '#111A24',
  border: '#1F2A37',
  textPrimary: '#E5E7DB',
  textSecondary: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
};
const mono = "'JetBrains Mono', monospace";
const body = "'Plus Jakarta Sans', sans-serif";

/* ───── Ghost pulse keyframe injection (once) ───── */
const KEYFRAME_ID = '__ghost-pulse-kf';
function ensureKeyframes() {
  if (typeof document === 'undefined') return;
  if (document.getElementById(KEYFRAME_ID)) return;
  const style = document.createElement('style');
  style.id = KEYFRAME_ID;
  style.textContent = `
    @keyframes ghostPulse {
      0%, 100% { opacity: 0.25; }
      50%      { opacity: 0.4; }
    }
  `;
  document.head.appendChild(style);
}

/* ═══════════════════════════════════════════════════
   useGhostData hook
   Retains the last good data snapshot so the table
   can show faded "ghost" rows while fresh data loads.
   ═══════════════════════════════════════════════════ */
export function useGhostData(data, loading) {
  const prevRef = useRef(null);
  useEffect(() => {
    if (data && data.length > 0 && !loading) {
      prevRef.current = data;
    }
  }, [data, loading]);
  return {
    ghostData: prevRef.current,
    isGhost: loading && !!prevRef.current,
  };
}

/* ═══════════════════════════════════════════════════
   GhostDataTable
   Props:
     columns      – [{ key, label, width, align, render, mono }]
     data         – current data rows (array | null)
     loading      – boolean
     previousData – stale snapshot to render as ghosts
     emptyMessage – string shown when no data at all
     onRowClick   – (row) => void
     sortable     – enable column sort (default true)
   ═══════════════════════════════════════════════════ */
export default function GhostDataTable({
  columns = [],
  data,
  loading = false,
  previousData,
  emptyMessage = 'No data to display',
  onRowClick,
  sortable = true,
}) {
  useEffect(ensureKeyframes, []);

  /* ── Sorting state ── */
  const [sortKey, setSortKey] = useState(null);
  const [sortDir, setSortDir] = useState('desc');

  const handleSort = (key) => {
    if (!sortable) return;
    if (sortKey === key) {
      setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'));
    } else {
      setSortKey(key);
      setSortDir('desc');
    }
  };

  /* ── Determine which rows to show ── */
  const isGhost = loading && !!previousData && previousData.length > 0;
  const rows = isGhost ? previousData : data || [];

  const sorted = useMemo(() => {
    if (!sortKey || !rows.length) return rows;
    return [...rows].sort((a, b) => {
      let va = a?.[sortKey];
      let vb = b?.[sortKey];
      if (typeof va === 'string') va = va.toLowerCase();
      if (typeof vb === 'string') vb = vb.toLowerCase();
      if (va == null) return 1;
      if (vb == null) return -1;
      if (va < vb) return sortDir === 'asc' ? -1 : 1;
      if (va > vb) return sortDir === 'asc' ? 1 : -1;
      return 0;
    });
  }, [rows, sortKey, sortDir]);

  /* ── Styles ── */
  const thStyle = {
    fontFamily: body,
    fontSize: 11,
    fontWeight: 600,
    color: C.textSecondary,
    textTransform: 'uppercase',
    letterSpacing: 1,
    padding: '10px 12px',
    textAlign: 'left',
    borderBottom: `1px solid ${C.border}`,
    backgroundColor: C.surface,
    position: 'sticky',
    top: 0,
    zIndex: 2,
  };

  const tdBase = {
    fontFamily: mono,
    fontSize: 13,
    padding: '10px 12px',
    borderBottom: `1px solid ${C.border}`,
    color: C.textPrimary,
  };

  /* Ghost row overrides */
  const ghostRowStyle = {
    opacity: 1, /* the animation handles pulse */
    pointerEvents: 'none',
    animation: 'ghostPulse 2s ease-in-out infinite',
  };

  const ghostCellOverride = {
    color: `${C.textSecondary}`,
    opacity: 0.35,
  };

  /* Wrapper transition for crossfade */
  const wrapperTransition = {
    transition: 'opacity 0.25s ease',
    opacity: loading && !isGhost ? 0.4 : 1,
  };

  /* ── Empty state ── */
  if (!loading && (!rows || rows.length === 0)) {
    return (
      <div
        style={{
          padding: 48,
          textAlign: 'center',
          backgroundColor: C.surface,
          border: `1px solid ${C.border}`,
          borderRadius: 10,
        }}
      >
        <div style={{ fontSize: 28, marginBottom: 8, opacity: 0.3, color: C.textSecondary }}>
          ---
        </div>
        <div style={{ fontFamily: body, fontSize: 14, color: C.textSecondary }}>
          {emptyMessage}
        </div>
      </div>
    );
  }

  return (
    <div
      style={{
        flex: 1,
        minHeight: 0,
        backgroundColor: C.surface,
        border: `1px solid ${C.border}`,
        borderRadius: 10,
        overflow: 'hidden',
        display: 'flex',
        flexDirection: 'column',
        ...wrapperTransition,
      }}
    >
      {/* Updating badge */}
      {isGhost && (
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 8,
            padding: '6px 12px',
            backgroundColor: `${C.amber}10`,
            borderBottom: `1px solid ${C.border}`,
          }}
        >
          <span
            style={{
              display: 'inline-block',
              width: 6,
              height: 6,
              borderRadius: '50%',
              backgroundColor: C.amber,
              animation: 'ghostPulse 1.5s ease-in-out infinite',
            }}
          />
          <span
            style={{
              fontFamily: body,
              fontSize: 11,
              fontWeight: 600,
              color: C.amber,
              textTransform: 'uppercase',
              letterSpacing: 0.5,
            }}
          >
            Updating...
          </span>
        </div>
      )}

      <div style={{ flex: 1, minHeight: 0, overflow: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              {columns.map((col) => (
                <th
                  key={col.key}
                  style={{
                    ...thStyle,
                    width: col.width || 'auto',
                    textAlign: col.align || 'left',
                    cursor: sortable ? 'pointer' : 'default',
                    userSelect: 'none',
                  }}
                  onClick={() => handleSort(col.key)}
                >
                  {col.label}{' '}
                  {sortKey === col.key && (
                    <span style={{ fontSize: 10, color: C.blue }}>
                      {sortDir === 'asc' ? '\u25B2' : '\u25BC'}
                    </span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sorted.map((row, i) => {
              const rowKey =
                row?.id || row?.symbol
                  ? `${row.id || row.symbol}-${i}`
                  : i;

              return (
                <tr
                  key={rowKey}
                  style={{
                    cursor: !isGhost && onRowClick ? 'pointer' : 'default',
                    transition: 'background 0.15s',
                    ...(isGhost ? ghostRowStyle : {}),
                  }}
                  onClick={() => {
                    if (!isGhost && onRowClick) onRowClick(row);
                  }}
                  onMouseEnter={(e) => {
                    if (!isGhost) e.currentTarget.style.backgroundColor = C.surface2;
                  }}
                  onMouseLeave={(e) => {
                    if (!isGhost) e.currentTarget.style.backgroundColor = 'transparent';
                  }}
                >
                  {columns.map((col) => {
                    const value = row?.[col.key];
                    const rendered = col.render
                      ? col.render(value, row)
                      : value ?? '--';

                    return (
                      <td
                        key={col.key}
                        style={{
                          ...tdBase,
                          textAlign: col.align || 'left',
                          fontFamily: col.mono !== false ? mono : body,
                          ...(isGhost ? ghostCellOverride : {}),
                        }}
                      >
                        {rendered}
                      </td>
                    );
                  })}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}
